/**
 * ClassificationSession entity with performance metrics
 *
 * Represents a batch classification session with enhanced audit capabilities
 * and parallel processing performance tracking.
 */

export interface ClassificationSession {
  id: string; // UUID
  startedAt: Date;
  completedAt?: Date;
  emailCount: number;
  successCount: number;
  errorCount: number;

  // Enhanced for new architecture
  processingMode: 'parallel' | 'sequential';
  batchSize: number;
  performanceMetrics: {
    totalDurationMs: number;
    avgEmailDurationMs: number;
    parallelStagesCount: number;
    databaseBatchOps: number;
  };

  // Configuration snapshot
  configVersion: string; // Hash of configuration used
  configSnapshot: object; // Full config for reproducibility

  // Error tracking
  errors: ClassificationError[];
  warnings: ClassificationWarning[];
}

export interface ClassificationError {
  emailId: string;
  stage: string;
  error: string;
  timestamp: Date;
  recoverable: boolean;
  retryCount: number;
}

export interface ClassificationWarning {
  emailId: string;
  stage: string;
  warning: string;
  timestamp: Date;
  impact: 'low' | 'medium' | 'high';
}

/**
 * Session processing modes:
 * - parallel: Multiple emails processed concurrently with parallel attribute detection
 * - sequential: One email at a time for debugging or low-resource environments
 */
export type ProcessingMode = 'parallel' | 'sequential';

/**
 * Performance tracking for parallel processing optimization
 */
export interface SessionPerformanceMetrics {
  totalDurationMs: number;
  avgEmailDurationMs: number;
  parallelStagesCount: number;
  databaseBatchOps: number;
  memoryUsageMB: number;
  peakConcurrency: number;
  stageExecutionTimes: Record<string, number>;
  parallelEfficiency: number; // Ratio of actual vs theoretical parallel speedup
}

